const d = $input.item.json.body || $input.item.json;
const side = d.side?.toUpperCase() || 'BUY';
const sideEmoji = side === 'BUY' ? '🟢' : '🔴';
const total = d.totalValue ? `$${Number(d.totalValue).toFixed(2)}` : 'N/A';
const price = d.price ? `$${Number(d.price).toFixed(2)}` : 'N/A';

return [{
  json: {
    ...d,
    discordMessage: `${sideEmoji} **Order Filled** | ${side} ${d.qty}x **${d.symbol}** @ ${price}\n💰 Total: ${total}\n🆔 Order: \`${d.orderId}\`\n⏱ ${new Date(d.timestamp || Date.now()).toLocaleString()}`,
    slackMessage: `${sideEmoji} *Order Filled* | ${side} ${d.qty}x *${d.symbol}* @ ${price} — Total: ${total}`,
    emailSubject: `[Alpha Terminal] Order Filled: ${side} ${d.qty} ${d.symbol}`,
    emailBody: `<h2>Order Executed</h2><table><tr><td><b>Action</b></td><td>${side}</td></tr><tr><td><b>Symbol</b></td><td>${d.symbol}</td></tr><tr><td><b>Quantity</b></td><td>${d.qty}</td></tr><tr><td><b>Price</b></td><td>${price}</td></tr><tr><td><b>Total Value</b></td><td>${total}</td></tr><tr><td><b>Order ID</b></td><td>${d.orderId}</td></tr><tr><td><b>Time</b></td><td>${new Date(d.timestamp || Date.now()).toLocaleString()}</td></tr></table>`
  }
}];
